template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then(sqlgen::write(records))
      .value();
}

template<typename ValueT>
void modify_eas_records_by_id(const std::string& table_name,
                               int record_id,
                               const std::string& col_name,
                               const ValueT& new_value) {
  // Determine the primary key column name based on table
  std::string pk_column;
  if (table_name == "Student") {
    pk_column = "SNo";
  } else if (table_name == "Course") {
    pk_column = "CID";
  } else if (table_name == "Score") {
    pk_column = "ScID";
  } else if (table_name == "Major") {
    pk_column = "MID";
  }

  // Build UPDATE SQL statement
  std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ";

  // Handle different value types for SQL formatting
  if constexpr (std::is_same_v<ValueT, std::string> || 
                std::is_convertible_v<ValueT, std::string>) {
    sql += "'" + std::string(new_value) + "'";
  } else if constexpr (std::is_arithmetic_v<ValueT>) {
    sql += std::to_string(new_value);
  } else {
    sql += "'" + std::string(new_value) + "'";
  }

  sql += " WHERE " + pk_column + " = ";

  // Handle different primary key types
  if (table_name == "Student") {
    sql += "'" + std::to_string(record_id) + "'";
  } else {
    sql += std::to_string(record_id);
  }

  sqlgen::sqlite::connect(db_path)
      .and_then([&sql](auto&& conn) {
        return sqlgen::exec(conn, sql);
      })
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  if (table_name == "Student") {
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Student> | where("SNo"_c == record_id))
        .value();
  } else if (table_name == "Course") {
    auto cid = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Course> | where("CID"_c == cid))
        .value();
  } else if (table_name == "Score") {
    auto scid = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Score> | where("ScID"_c == scid))
        .value();
  } else if (table_name == "Major") {
    auto mid = static_cast<uint32_t>(std::stoul(record_id));
    sqlgen::sqlite::connect(db_path)
        .and_then(sqlgen::remove<Major> | where("MID"_c == mid))
        .value();
  }
}
