    rfl::Default<std::optional<int>, 1> Term;  // NULL DEFAULT 1
    std::optional<int> CTime;              // NULL
    rfl::Default<float, 0> Credit;         // NOT NULL DEFAULT 0
  };

  struct Score {
    std::string SNo;                       // FK to Student
    int CID;                               // FK to Course
    std::optional<float> Score;            // NULL
  };

  void design_eas_database() {
    // Connect to SQLite database
    auto connector = sqlgen::sqlite::Connector("test_db.sqlite");

    // Create Student table
    connector.create_table<Student>();

    // Create Course table
    connector.create_table<Course>();

    // Create Score table with composite primary key and foreign keys
    // Note: Due to composite primary key requirements, we use raw SQL
    connector.execute(R"(
      CREATE TABLE IF NOT EXISTS Score (
        SNo VARCHAR(10) NOT NULL,
        CID INT NOT NULL,
        Score FLOAT NULL,
        PRIMARY KEY (SNo, CID),
        FOREIGN KEY (SNo) REFERENCES Student(SNo),
        FOREIGN KEY (CID) REFERENCES Course(CID)
      )
    )");
  }

}

