    // Build the SQL query for joining Product and Sale tables
    // Group by category, calculate totals, and filter by HAVING clause
    const auto sql = R"(
        SELECT p.category, SUM(s.quantity) as total_qty, SUM(s.amount) as total_amt
        FROM Product p
        INNER JOIN Sale s ON p.product_id = s.product_id
        GROUP BY p.category
        HAVING total_amt > 5000
    )";

    // Execute the query and return results as vector of CategoryReport
    auto results = db.query<CategoryReport>(sql);

    return results;
}

}  // namespace query_product_sales_report

