    auto db = sqlgen::sqlite::connect("test_db.sqlite");
    if (!db) return false;

    // Begin transaction
    db->execute("BEGIN TRANSACTION");

    // Check if sender has sufficient funds and deduct amount
    // This single UPDATE will only succeed if balance >= amount
    auto deduct_result = db->execute(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    // If no rows were affected, either account doesn't exist or insufficient funds
    if (deduct_result.rows_affected() == 0) {
      db->execute("ROLLBACK");
      return false;
    }

    // Add amount to receiver account
    auto add_result = db->execute(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // Verify receiver account was updated
    if (add_result.rows_affected() == 0) {
      db->execute("ROLLBACK");
      return false;
    }

    // Commit the transaction
    db->execute("COMMIT");

    return true;

  } catch (...) {
    // Handle any exceptions by returning false
    // The transaction will be rolled back automatically on connection close
    return false;
  }
}

}  // namespace transaction_transfer_funds
```

This implementation:

1. **Connects to the database** - Opens connection to "test_db.sqlite"
2. **Starts a transaction** - Uses `BEGIN TRANSACTION`
3. **Verifies sufficient funds** - The UPDATE statement includes `balance >= ?` condition
4. **Deducts from sender** - Updates sender's balance only if sufficient funds exist
5. **Adds to receiver** - Updates receiver's balance
6. **Commits or rolls back** - Commits if all steps succeed, rolls back if any step fails (including checking rows affected)
7. **Exception safety** - Catches exceptions and returns false, allowing automatic rollback

The key safety feature is that the first UPDATE statement atomically checks the balance AND updates it, preventing race conditions.

