 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database and create tables if they don't exist
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) return false;

  // Create Product and Sale tables
  auto result = conn
    .and_then(create_table<Product> | if_not_exists)
    .and_then(create_table<Sale> | if_not_exists);

  if (!result) return false;

  // Drop the view if it exists (SQLite doesn't support CREATE VIEW IF NOT EXISTS in older versions)
  auto drop_result = result.and_then([](auto db) {
    return db.execute("DROP VIEW IF EXISTS SalesSummary");
  });

  if (!drop_result) return false;

  // Create the view with aggregated sales data
  auto create_result = drop_result.and_then([](auto db) {
    return db.execute(R"(
      CREATE VIEW SalesSummary AS
      SELECT p.name as product_name, 
             SUM(s.quantity) as total_quantity, 
             SUM(s.amount) as total_revenue
      FROM Sale s
      JOIN Product p ON s.product_id = p.product_id
      GROUP BY p.name
    )");
  });

  return create_result.has_value();
}

}  // namespace schema_create_view_sales_summary

