};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;

  // Note: SQLite doesn't support RIGHT JOIN natively, so we use LEFT JOIN
  // with reversed table order to achieve the same result.
  // This query includes all projects and matches them with departments where available.
  // If we want all departments instead, we would swap the tables.

  // Connect to the database and execute the join query
  auto result = sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      // Simulating RIGHT JOIN: Department RIGHT JOIN Project
      // Equivalent to: Project LEFT JOIN Department
      // This includes all projects with their department info (if available)
      const std::string query = R"(
        SELECT d.name as department_name, p.name as project_name 
        FROM Project p 
        LEFT JOIN Department d ON p.department_id = d.department_id
      )";

      return conn.template execute<std::vector<DepProj>>(query);
    });

  // Return the result or empty vector if query failed
  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
```

**Note:** Since SQLite doesn't support `RIGHT JOIN` directly, the implementation uses `LEFT JOIN` with the tables in reversed order to achieve the equivalent result. The query `Project LEFT JOIN Department` is equivalent to `Department RIGHT JOIN Project`, which includes all projects and optionally matches them with their departments. This matches the structure of `DepProj` where `department_name` is optional and `project_name` is required.

