#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database, create table if it doesn't exist,
  // perform insert or replace (upsert), and read back to verify
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
                    .and_then(create_table<Inventory> | if_not_exists)
                    .and_then(insert_or_replace(items))
                    .and_then(read<std::vector<Inventory>>);

  // Return true if the operation succeeded and we can read back the data
  return result.has_value();
}

}  // namespace upsert_inventory_items
```

This implementation:

1. **Connects to the SQLite database** `test_db.sqlite` using `sqlgen::sqlite::connect()`
2. **Creates the Inventory table** if it doesn't exist using `create_table<Inventory> | if_not_exists`
3. **Performs upsert operations** using `insert_or_replace(items)` which will insert new items or replace existing ones based on the primary key (`item_id`)
4. **Reads back the items** using `read<std::vector<Inventory>>` to verify the operation succeeded
5. **Returns success status** by checking if the result has a value (indicating all operations completed successfully)

The function follows the sqlgen pattern of chaining operations with `.and_then()`, where each operation depends on the success of the previous one.

