namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

// Helper functions to demonstrate trim operations (ltrim, rtrim, trim)
inline std::string ltrim(const std::string& s) {
  auto start = std::find_if_not(s.begin(), s.end(), 
                                 [](unsigned char ch) { return std::isspace(ch); });
  return std::string(start, s.end());
}

inline std::string rtrim(const std::string& s) {
  auto end = std::find_if_not(s.rbegin(), s.rend(),
                               [](unsigned char ch) { return std::isspace(ch); });
  return std::string(s.begin(), end.base());
}

inline std::string trim(const std::string& s) {
  return ltrim(rtrim(s));
}

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Read UserProfile data from the database
  auto profiles_result = conn.and_then([](auto connection) {
    return sqlgen::read<std::vector<UserProfile>>(connection);
  });

  // Get the profiles or return empty vector on error
  auto profiles = profiles_result.value_or(std::vector<UserProfile>{});

  // Transform UserProfile to ValidatedProfile with trimming and length calculation
  std::vector<ValidatedProfile> result;
  result.reserve(profiles.size());

  for (const auto& profile : profiles) {
    ValidatedProfile validated;
    validated.user_id = profile.user_id;

    // Apply trim operations (demonstrating ltrim, rtrim, and trim)
    validated.trimmed_name = trim(profile.name);
    validated.trimmed_email = trim(profile.email);

    // Calculate length of trimmed strings
    validated.name_length = static_cast<int>(validated.trimmed_name.length());
    validated.email_length = static_cast<int>(validated.trimmed_email.length());

    result.push_back(validated);
  }

  return result;
}

}  // namespace trim_and_length_validation
