namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Execute UPDATE to replace "foo" with "bar" in content
  db.and_then([](auto conn) {
    return conn.execute("UPDATE Notes SET content = REPLACE(content, 'foo', 'bar')");
  });

  // Read and return updated notes
  // Note: We select content as updated_content to match the UpdatedNote structure
  auto result = db.and_then([](auto conn) {
    return conn.template execute_query<std::vector<UpdatedNote>>(
      "SELECT note_id, content as updated_content FROM Notes"
    );
  });

  return result.value_or(std::vector<UpdatedNote>{});
}

