```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it using UNION
  // LEFT JOIN gets all suppliers with their products (if any)
  // UNION with products that don't have matching suppliers
  const std::string query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT s.name as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
      .and_then(sqlgen::read<std::vector<SupProd>>(query));

  // Return the result if successful, otherwise return empty vector
  if (result) {
    return *result;
  }
  return std::vector<SupProd>{};
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`

2. **Simulates FULL JOIN** since SQLite doesn't natively support FULL OUTER JOIN:
   - First part: `LEFT JOIN` from Supplier to Product - gets all suppliers with their matching products (or NULL if no match)
   - Second part: `UNION` with a `LEFT JOIN` from Product to Supplier filtered by `WHERE s.supplier_id IS NULL` - gets products without matching suppliers

3. **Returns joined results** as a vector of `SupProd` structs containing supplier names and optional product names

4. **Handles errors** by returning an empty vector if the database operation fails

The query ensures all rows from both tables are included in the result, which satisfies the FULL JOIN requirement.

