```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Execute raw SQL query to analyze sales by weekday
  // strftime('%w', sale_time) extracts weekday (0=Sunday, 1=Monday, ..., 6=Saturday)
  // Group by weekday and sum the quantities
  const std::string query = 
    "SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday, "
    "SUM(quantity) as total_quantity "
    "FROM Sales "
    "GROUP BY strftime('%w', sale_time) "
    "ORDER BY weekday";

  // Execute query and return results
  auto results = db.execute<WeekdayStats>(query);

  return results;
}

}  // namespace weekday_sales_analysis
```

This implementation:

1. **Connects to the database** using `sqlgen::sqlite::connect()` with the database file "test_db.sqlite"

2. **Extracts weekday from sale_time** using SQLite's `strftime('%w', sale_time)` function, which returns the day of week as:
   - 0 = Sunday
   - 1 = Monday
   - 2 = Tuesday
   - ...
   - 6 = Saturday

3. **Aggregates totals per weekday** by:
   - Using `SUM(quantity)` to total the quantities
   - Using `GROUP BY strftime('%w', sale_time)` to group by weekday
   - Using `ORDER BY weekday` to sort the results

4. **Returns weekday metrics** as a `std::vector<WeekdayStats>` containing the weekday number and total quantity for each day of the week

