#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Connect to SQLite database
  auto db = sqlite::Connection("test_db.sqlite");

  // SQL query with SQLite-specific temporal functions
  // SQLite uses strftime() for date/time extraction and julianday() for date arithmetic
  const std::string query = R"(
    SELECT p.project_id, p.name,
           CAST(strftime('%d', t.start_time) AS INTEGER) as day,
           CAST(strftime('%m', t.start_time) AS INTEGER) as month,
           CAST(strftime('%Y', t.start_time) AS INTEGER) as year,
           CAST(strftime('%H', t.start_time) AS INTEGER) as hour,
           CAST(strftime('%M', t.start_time) AS INTEGER) as minute,
           CAST(strftime('%S', t.start_time) AS INTEGER) as second,
           julianday(t.end_time) - julianday(t.start_time) as duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
  )";

  // Execute query and return results mapped to TimeMetrics structure
  return db.execute<TimeMetrics>(query);
}

}  // namespace project_time_tracking
```

**Key Implementation Details:**

1. **Database Connection**: Opens connection to "test_db.sqlite" using `sqlite::Connection`

2. **SQLite Temporal Functions**:
   - `strftime('%d', ...)` - extracts day
   - `strftime('%m', ...)` - extracts month
   - `strftime('%Y', ...)` - extracts year
   - `strftime('%H', ...)` - extracts hour
   - `strftime('%M', ...)` - extracts minute
   - `strftime('%S', ...)` - extracts second
   - `julianday(end_time) - julianday(start_time)` - calculates days between timestamps

3. **JOIN Operation**: Inner join between Project and TimeLog tables on `project_id`

4. **Result Mapping**: The `execute<TimeMetrics>()` method automatically maps query results to the `TimeMetrics` struct based on column names and types

