```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open connection to SQLite database
  auto db = sqlite::open("test_db.sqlite");

  // Execute query with join, group by, and aggregations
  auto results = db.execute<Stats>(
    "SELECT u.user_id, u.name, COUNT(*) as post_count, AVG(LENGTH(p.content)) as avg_length "
    "FROM User u "
    "JOIN Post p ON u.user_id = p.user_id "
    "GROUP BY u.user_id, u.name"
  );

  return results;
}

}  // namespace group_by_with_aggregations
```

This implementation:
1. **Connects to the database**: Uses `sqlite::open("test_db.sqlite")` to connect to the SQLite database
2. **Groups posts per user**: Uses `GROUP BY u.user_id, u.name` to group by user
3. **Computes aggregations**: 
   - `COUNT(*)` for the number of posts per user (post_count)
   - `AVG(LENGTH(p.content))` for the average content length (avg_length)
4. **Returns the results**: The query results are automatically mapped to the `Stats` struct and returned as a vector

The query joins the User and Post tables on user_id, groups the results by user, and calculates the required aggregations.

